const item = $input.first().json;
const body = item.body || {};
const query = item.query || {};

const cleanEmail = (raw) => {
  const first = String(raw || '').trim().toLowerCase().split(/\n/)[0].trim();
  return first.split(/\s+regards/i)[0].trim();
};

const session_id = String(body.sessionId || body.session_id || query.sessionId || query.session_id || '').trim();
const candidate_email = cleanEmail(body.email || body.candidate_email || query.email || query.candidate_email);
const answer = String(body.answer || query.answer || '').trim();
const current_phase = parseInt(body.phase || body.current_phase || query.phase || '1', 10);
const tab_switches = parseInt(body.tabSwitches ?? body.tab_switches ?? '0', 10);

const nested = item.config || {};
const config = {
  supabase_url: nested.supabase_url || item.supabase_url || '',
  supabase_key: nested.supabase_key || item.supabase_key || '',
  gemini_model: nested.gemini_model || nested.groq_model || item.gemini_model || item.groq_model || '',
  groq_model: nested.groq_model || item.groq_model || '',
  max_questions: Number(nested.max_questions ?? item.max_questions ?? 5),
  interviewer_email: nested.interviewer_email || item.interviewer_email || '',
  organization_name: nested.organization_name || item.organization_name || '',
  requisition_title: nested.requisition_title || '',
  requisition_requirements: nested.requisition_requirements || '',
  table_assessment_sessions: nested.table_assessment_sessions || 'assessment_sessions',
};

return [{ json: { session_id, candidate_email, answer, current_phase, tab_switches, config } }];

// n8n: CODE - Build LLM context (assessment phases 1–5)
// WORKFLOW: Assessment Answer workflow ONLY (NOT Live Speech)
// NODE: CODE - Build LLM context (before Basic LLM Chain)
// Requires upstream: CODE - Normalize Data
// Source file: n8n_code_build_llm_context.js — never paste parse_live_speech_result.js here.

let norm;
try {
  norm = $('CODE - Normalize Data').first().json;
} catch (_) {
  throw new Error(
    'Wrong code in this node. Paste n8n_code_build_llm_context.js into "CODE - Build LLM context". ' +
    'If you see "Normalize Live Speech Complete" errors, you accidentally pasted n8n_code_parse_live_speech_result.js.'
  );
}
const raw = $input.first().json;
const session = Array.isArray(raw) ? raw[0] : raw;
if (!session?.id) {
  throw new Error('No assessment session row for id=' + norm.session_id);
}

let history = session.interview_history;
if (typeof history === 'string') {
  try {
    history = JSON.parse(history);
  } catch (e) {
    history = [];
  }
}
if (!Array.isArray(history)) history = [];

let sessionConfig = session.config;
if (typeof sessionConfig === 'string') {
  try {
    sessionConfig = JSON.parse(sessionConfig);
  } catch (e) {
    sessionConfig = {};
  }
}
if (!sessionConfig || typeof sessionConfig !== 'object') sessionConfig = {};

const cfg = {
  ...norm.config,
  ...sessionConfig,
  requisition_title:
    sessionConfig.requisition_title || norm.config?.requisition_title || '',
  requisition_requirements:
    sessionConfig.requisition_requirements || norm.config?.requisition_requirements || '',
  groq_model:
    sessionConfig.groq_model || norm.config?.groq_model || 'llama-3.3-70b-versatile',
  max_questions: Number(sessionConfig.max_questions || norm.config?.max_questions || 5),
  fail_score_threshold: Number(
    sessionConfig.fail_score_threshold ?? norm.config?.fail_score_threshold ?? 30
  ),
  pass_score_threshold: Number(
    sessionConfig.pass_score_threshold ?? norm.config?.pass_score_threshold ?? 60
  ),
  timer_min_seconds: Number(sessionConfig.timer_min_seconds ?? norm.config?.timer_min_seconds ?? 60),
  timer_max_seconds: Number(sessionConfig.timer_max_seconds ?? norm.config?.timer_max_seconds ?? 600),
  speech_enabled:
    sessionConfig.speech_enabled === true ||
    sessionConfig.speech_enabled === 'true' ||
    norm.config?.speech_enabled === true ||
    Number(sessionConfig.speech_phases ?? norm.config?.speech_phases ?? 0) > 0,
  speech_phases: Number(sessionConfig.speech_phases ?? norm.config?.speech_phases ?? 5),
};

const ph = Number(norm.current_phase || 1);
const maxQ = Number(cfg.max_questions || 5);
const isFinal = ph >= maxQ;
const failThreshold = Number(cfg.fail_score_threshold ?? 30);

const jdTitle = String(cfg.requisition_title || '').trim();
const jdReq = String(cfg.requisition_requirements || '').trim();
if (!jdTitle || !jdReq) {
  throw new Error(
    'JD missing on assessment session. Complete CV screening with recruiter form JD first (session.config.requisition_title / requisition_requirements).'
  );
}

function extractJdThemes(text) {
  const lines = String(text)
    .split(/\r?\n|(?<=[.;])\s+/)
    .flatMap((chunk) => chunk.split(/\s*[•\-*]\s+/))
    .map((s) => s.replace(/^[\s\d.)(]+/, '').trim())
    .filter((s) => s.length >= 12);
  return lines.length ? [...new Set(lines)].slice(0, 10) : [String(text).slice(0, 500)];
}

function inferExperienceTier(cvText) {
  const cv = String(cvText || '');
  const yearMatches = [...cv.matchAll(/(\d+)\+?\s*(?:years?|yrs?)(?:\s+of)?\s*(?:experience|exp)?/gi)];
  let maxYears = 0;
  for (const m of yearMatches) {
    const n = Number(m[1]);
    if (Number.isFinite(n) && n > maxYears) maxYears = n;
  }
  if (/\b(senior|lead|principal|architect|staff|head of|engineering manager)\b/i.test(cv) || maxYears >= 6) {
    return 'senior';
  }
  if (/\b(junior|intern|trainee|graduate|entry[- ]?level|fresher|bootcamp)\b/i.test(cv) || maxYears <= 2) {
    return 'junior';
  }
  return 'mid';
}

function stackHints(jdReq) {
  const jd = String(jdReq || '').toLowerCase();
  if (/\.net|asp\.net|c#|ef core|entity framework|linq/i.test(jd)) {
    return 'ASP.NET Core, REST, JWT/OAuth, EF Core, LINQ, middleware, DI';
  }
  if (/node|javascript|typescript|react/i.test(jd)) {
    return 'Node/JS APIs, REST, JWT, async I/O, HTTP';
  }
  if (/python|django|flask|fastapi/i.test(jd)) {
    return 'Python web APIs, REST, auth, ORM, HTTP';
  }
  return 'REST APIs, HTTP, auth, databases, backend fundamentals';
}

function phaseBlueprint(phaseNum, tier, jdReq) {
  const stack = stackHints(jdReq);
  const depth =
    tier === 'senior' ? 'advanced trade-offs and edge cases' : tier === 'junior' ? 'clear fundamentals' : 'solid mid-level reasoning';
  const lanes = {
    2: `Comparative concept from ${stack} — "what is the difference between X and Y?" or "when would you choose X over Y?" (${depth}).`,
    3: `Why / how-it-works — explain the reasoning behind a core idea in ${stack} (e.g. stateless REST, token auth, ORM behavior) (${depth}).`,
    4: `Failure or symptom reasoning — given a realistic symptom, explain likely causes and your diagnostic thinking — no code, no architecture design (${depth}).`,
    5: `Judgment — one conceptual scenario requiring a reasoned choice between options with justification; tie to ${stack} (${depth}).`,
  };
  return lanes[phaseNum] || `Follow-up conceptual probe on ${stack} aligned to prior answers (${depth}).`;
}

const cvText = String(session.cv_plaintext || '').slice(0, 8000);
const experienceTier = inferExperienceTier(cvText);
const jdThemes = extractJdThemes(jdReq).join('\n- ');
const historyText = history
  .map(
    (h) =>
      `Phase ${h.phase} Q: ${h.question_text || h.question || ''} | A: ${h.answer_text ?? 'pending'} | Score: ${h.score ?? 'N/A'}`
  )
  .join('\n');

const themesAsked = history
  .filter((h) => h.question_text || h.question)
  .map((h) => `Phase ${h.phase}: ${String(h.question_text || h.question).slice(0, 140)}`)
  .join('\n');

const currentQuestionRow = history.find((h) => Number(h.phase) === ph);
const currentQuestionText = String(
  currentQuestionRow?.question_text || currentQuestionRow?.question || ''
).trim();

const prevPhaseRow = history.find((h) => Number(h.phase) === ph - 1);
const prevTimeLimit = prevPhaseRow?.time_limit_seconds ?? null;

const nextPhaseNum = ph + 1;

const questionRules = `ASSESSMENT QUESTION RULES (next_question and first_speech_question):
Written technical assessment — conceptual and logic-based only. Sound like a real interviewer.

Silent personalization (CV + JD internal only):
- Experience level: ${experienceTier}
- Role stack: ${stackHints(jdReq)}
- Pick topics in BOTH JD and CV; do not repeat themes already asked
- Calibrate depth to prior answers

Phase focus for next_question (phase ${nextPhaseNum}):
- ${phaseBlueprint(nextPhaseNum, experienceTier, jdReq)}

Question style (REQUIRED):
- Comparative: "What is the difference between X and Y?"
- Reasoning: "Why do teams use X instead of Y?" / "What problem does X solve?"
- Conceptual scenarios: symptom → explain likely causes (reasoning only)
- One clear question only — no multi-part lists
- Answers may exist online — test understanding and explanation quality, not memorized CV stories

GOOD examples:
- "What is the difference between JWT-based authentication and server-side session cookies, and when would you prefer each?"
- "Why are REST APIs typically stateless, and what problems does that solve?"
- "What is the difference between authentication and authorization?"

STRICTLY FORBIDDEN — never ask:
- Coding: write code, implement, algorithms, syntax, debug this snippet
- Design exercises: design a system/architecture, microservices layout, scalability design
- Implementation recipes: step-by-step how to build or configure something in code
- Generic fluff: "What is OOP?", "Explain REST in one sentence" with no role context
- CV quoting: "on your CV", company names, project titles, "At [Company]…"

BAD: "Design a rate-limited microservices architecture for our platform."
BAD: "Write a C# method to implement pagination."
BAD: "On your CV you used JWT at Acme — tell us about that."`;

const sharedRules = `"""You are an experienced technical interviewer for ${jdTitle}.

You have the job description, the candidate CV (for silent calibration only), and the full Q&A history below. Interview like a real hiring manager.

Each phase (except the last):
- Score the answer to the question asked this phase: 0-100
- Give honest feedback and a concise suggested_answer
- Write next_question: the single best follow-up for phase ${nextPhaseNum}

Final phase:
- Score the answer, then decide PASS or FAIL for the technical round overall

Scoring guidance:
- Do not repeat topics you already covered
- Calibrate difficulty to experience level (${experienceTier}) and prior answers
- Empty, timeout, or [SYSTEM TERMINATION] answers: score 0-15

${questionRules}

Job title: ${jdTitle}
Key JD themes:
- ${jdThemes || jdReq.slice(0, 500)}

Candidate CV (silent calibration — never quote in questions):
${cvText || '(none)'}

Prior Q&A:
${historyText || '(none yet)'}

Topics already asked:
${themesAsked || '(none yet)'}

Tab switches: ${norm.tab_switches || 0}`;

const speechEnabled =
  cfg.speech_enabled === true ||
  cfg.speech_enabled === 'true' ||
  Number(cfg.speech_phases || 0) > 0;

let systemContent;
if (isFinal) {
  const speechHandoff = speechEnabled
    ? `

If speech round is enabled (${cfg.speech_phases} voice questions after technical), also include first_speech_question — a natural spoken behavioral opener for the communication round. Apply the same FORBIDDEN rules (no CV/company names in the question text).`
    : '';

  const speechField = speechEnabled
    ? ',"first_speech_question":string'
    : '';

  systemContent = `${sharedRules}

Current phase: ${ph} of ${maxQ} (FINAL).
Question asked this phase:
${currentQuestionText || '(see prior Q&A)'}

Answer to grade:
${norm.answer}
${speechHandoff}

Tasks:
1. Score the answer 0-100 using your judgment.
2. Decide PASS or FAIL for the technical round.
3. feedback + suggested_answer.

Output: {"status":"finished","result":"PASS"|"FAIL","score":number,"feedback":string,"suggested_answer":string,"next_question":""${speechField}}`;
} else {
  systemContent = `${sharedRules}

Current phase: ${ph} of ${maxQ}.
Question asked this phase:
${currentQuestionText || '(see prior Q&A)'}

Answer to grade:
${norm.answer}
${prevTimeLimit != null ? `Previous phase time_limit_seconds: ${prevTimeLimit}` : ''}

Tasks:
1. Score the answer 0-100.
2. feedback + suggested_answer.
3. next_question for phase ${nextPhaseNum} — follow ASSESSMENT QUESTION RULES above.
4. time_limit_seconds (90-600) + complexity_tier (A-D).

Output: {"score":number,"feedback":string,"suggested_answer":string,"next_question":string,"time_limit_seconds":number,"complexity_tier":"A"|"B"|"C"|"D"}`;
}

const body = {
  model: cfg.groq_model || 'llama-3.3-70b-versatile',
  messages: [
    { role: 'system', content: systemContent },
    { role: 'user', content: 'Evaluate and respond with JSON only.' },
  ],
  temperature: isFinal ? 0.25 : 0.55,
  response_format: { type: 'json_object' },
};

return [
  {
    json: {
      groq_assessment_request: body,
      prompt: systemContent,
      session,
      norm: { ...norm, config: cfg },
      isFinal,
      failThreshold,
      current_question_text: currentQuestionText,
    },
  },
];

// n8n: CODE - Parse Result (assessment scoring)
// Paste into: CODE - Parse Result (after Groq/Gemini/Basic LLM Chain)
// Replaces: CODE - Update interview_history if that is your node name

function timerBounds(config) {
  const min = Number(config?.timer_min_seconds);
  const max = Number(config?.timer_max_seconds);
  return {
    min: Number.isFinite(min) && min > 0 ? min : 60,
    max: Number.isFinite(max) && max > 0 ? max : 600,
  };
}

function clampSeconds(sec, config) {
  const { min, max } = timerBounds(config);
  return Math.min(max, Math.max(min, Math.round(sec)));
}

// Seconds band per complexity tier
function tierTimeRange(tier) {
  switch (String(tier || '').toUpperCase()) {
    case 'A':
      return [60, 120];
    case 'B':
      return [150, 240];
    case 'C':
      return [270, 390];
    case 'D':
      return [420, 600];
    default:
      return null;
  }
}

// Infer a tier when the model omits or returns a junk tier
function inferTierFromQuestion(questionText) {
  const q = String(questionText || '');
  const words = q.trim().split(/\s+/).filter(Boolean).length;
  const subParts =
    (q.match(/\?/g) || []).length +
    (q.match(/\b(and|also|furthermore|additionally|then|as well as)\b/gi) || []).length;
  const heavy =
    /\b(architecture|design|schema|scalable|scalability|concurrency|distributed|trade-?off|optimi[sz]e|throughput|migration|pipeline|multi-?tenant|security|performance|caching|indexing)\b/i.test(
      q
    );

  if (words <= 28 && subParts <= 1 && !heavy) return 'A';
  if (words >= 80 || (heavy && subParts >= 3)) return 'D';
  if (words >= 50 || heavy) return 'C';
  return 'B';
}

// Deterministic per-question time: tier sets the band, question length positions
// within it, the model's value (if sane) is blended in. Different questions →
// different times, longer/harder questions → more seconds.
function deriveTimeLimitSeconds(rawLlmTime, tier, questionText, config, phase) {
  const usableTier =
    tierTimeRange(tier) ? tier : inferTierFromQuestion(questionText);
  const [lo, hi] = tierTimeRange(usableTier) || [150, 240];

  const words = String(questionText || '').trim().split(/\s+/).filter(Boolean).length;
  const span = Math.max(1, 90 - 20);
  const t = Math.max(0, Math.min(1, (words - 20) / span));
  let computed = lo + t * (hi - lo);

  const llm = Number(rawLlmTime);
  if (Number.isFinite(llm) && llm >= lo && llm <= hi) {
    computed = (llm + computed) / 2;
  }

  let sec = Math.round(computed / 15) * 15;
  sec = Math.max(lo, Math.min(hi, sec));
  return { seconds: clampSeconds(sec, config), tier: usableTier };
}

function buildDeadline(isoStart, seconds) {
  const start = isoStart ? new Date(isoStart) : new Date();
  return new Date(start.getTime() + seconds * 1000).toISOString();
}

function extractLlmText(api) {
  if (!api || typeof api !== 'object') return '';
  if (typeof api.text === 'string' && api.text.trim()) return api.text.trim();
  if (typeof api.output === 'string' && api.output.trim()) return api.output.trim();
  if (typeof api.response === 'string' && api.response.trim()) return api.response.trim();
  const c0 = api.choices?.[0];
  if (c0?.message?.content) return String(c0.message.content).trim();
  if (typeof c0?.text === 'string') return c0.text.trim();
  const parts = api.candidates?.[0]?.content?.parts;
  if (Array.isArray(parts) && parts[0]?.text) return String(parts[0].text).trim();
  return '';
}

function salvageNextQuestionFromText(rawText) {
  const text = String(rawText || '');
  if (!text.trim()) return '';

  const patterns = [
    /"next_question"\s*:\s*"((?:\\.|[^"\\])*)"/i,
    /"nextQuestion"\s*:\s*"((?:\\.|[^"\\])*)"/i,
    /next_question\s*[:=]\s*"((?:\\.|[^"\\])*)"/i,
  ];
  for (const re of patterns) {
    const m = text.match(re);
    if (m?.[1]) {
      return m[1].replace(/\\n/g, '\n').replace(/\\"/g, '"').replace(/\\\\/g, '\\').trim();
    }
  }
  return '';
}

function parseLlmContent(api) {
  if (
    api &&
    (api.score != null ||
      api.feedback ||
      api.next_question ||
      api.nextQuestion ||
      api.result ||
      api.status === 'finished')
  ) {
    const nextQ = String(api.next_question || api.nextQuestion || api.question || '').trim();
    if (!nextQ) {
      const salvaged = salvageNextQuestionFromText(extractLlmText(api));
      if (salvaged) {
        return { ...api, next_question: salvaged, nextQuestion: salvaged };
      }
    }
    return api;
  }
  const rawText = extractLlmText(api);
  if (!rawText) {
    return {
      status: 'in_progress',
      score: 0,
      feedback: 'Empty model output.',
      next_question: '',
      nextQuestion: '',
    };
  }
  try {
    const cleaned = rawText.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
    const parsed = JSON.parse(cleaned);
    const nextQ = String(parsed.next_question || parsed.nextQuestion || parsed.question || '').trim();
    if (!nextQ) {
      const salvaged = salvageNextQuestionFromText(rawText);
      if (salvaged) {
        parsed.next_question = salvaged;
        parsed.nextQuestion = salvaged;
      }
    }
    return parsed;
  } catch (e) {
    const salvaged = salvageNextQuestionFromText(rawText);
    return {
      status: 'in_progress',
      score: 0,
      feedback: salvaged ? 'Recovered question from partial model output.' : 'Could not parse model output.',
      next_question: salvaged,
      nextQuestion: salvaged,
    };
  }
}

function extractJdThemes(text) {
  const lines = String(text)
    .split(/\r?\n|(?<=[.;])\s+/)
    .flatMap((chunk) => chunk.split(/\s*[•\-*]\s+/))
    .map((s) => s.replace(/^[\s\d.)(]+/, '').trim())
    .filter((s) => s.length >= 12);
  return lines.length ? [...new Set(lines)].slice(0, 10) : [String(text).slice(0, 400)];
}

function extractCvAnchors(text) {
  const cv = String(text || '');
  const projects =
    cv.match(/(?:project|built|developed|engineered|implemented|led)[^.]{10,120}/gi) || [];
  const skills =
    cv.match(
      /\b(React|Angular|Vue|Node\.?js|Python|Django|Flask|SQL|PostgreSQL|MySQL|MongoDB|\.NET|ASP\.NET|C#|Java|Spring|AWS|Azure|GCP|Docker|Kubernetes|Redis|Kafka|REST|GraphQL|TypeScript|JavaScript|EF\s*Core|LINQ|JWT|OAuth|microservices?|APIM|CI\/CD|GitHub Actions)\b/gi
    ) || [];
  return [
    ...new Set([
      ...projects.slice(0, 5).map((p) => p.trim().slice(0, 80)),
      ...skills.slice(0, 6),
    ]),
  ].filter(Boolean);
}

function buildFallbackNextQuestion(ph, history, cfg, session) {
  const nextPhase = ph + 1;
  const jdReq = String(cfg.requisition_requirements || '').trim().toLowerCase();
  const isDotNet = /\.net|asp\.net|c#|ef core|entity framework/i.test(jdReq);

  const dotnetFundamentals = [
    'Why are REST APIs typically stateless? What problems does statelessness solve?',
    'What is dependency injection and why is it useful in ASP.NET Core applications?',
    'What is the difference between IEnumerable and IQueryable in LINQ? When would you use each?',
    'How does JWT-based authentication work at a high level?',
    'What is the purpose of middleware in the ASP.NET Core request pipeline?',
  ];
  const dotnetApplied = [
    'An API endpoint suddenly returns 500 errors under load — what are the most likely causes and how would you narrow them down?',
    'What is the difference between optimistic and pessimistic concurrency, and when would you use each?',
    'Why might you choose no-tracking queries in EF Core, and what trade-off are you accepting?',
    'What does idempotency mean for HTTP APIs, and why does it matter for retries?',
    'Cookie-based session auth vs JWT for an API — what are the main trade-offs?',
  ];
  const genericFundamentals = [
    'What is the difference between SQL INNER JOIN and LEFT JOIN? When would you use each?',
    'What is the difference between authentication and authorization?',
    'Why are REST APIs typically stateless, and what problems does statelessness solve?',
    'What is idempotency in HTTP APIs and why does it matter?',
    'What is the difference between synchronous and asynchronous processing in a web service?',
  ];
  const genericApplied = [
    'An API is slow only under peak traffic — what categories of causes would you consider first?',
    'What is the difference between a 401 and a 403 response, and when should each be returned?',
    'Caching can speed up APIs — what are common reasons a cache causes stale or wrong data?',
    'What is the difference between PUT and PATCH, and when would you use each?',
    'Token-based auth vs server-side sessions — what are the main trade-offs for a public API?',
  ];

  const fundamentals = isDotNet ? dotnetFundamentals : genericFundamentals;
  const applied = isDotNet ? dotnetApplied : genericApplied;

  const asked = (history || [])
    .map((h) => String(h.question_text || '').toLowerCase())
    .filter(Boolean);

  const pool =
    nextPhase <= 2
      ? fundamentals
      : nextPhase <= 4
        ? applied
        : [applied[applied.length - 1]];

  for (const q of pool) {
    const key = q.slice(0, 40).toLowerCase();
    if (!asked.some((a) => a.includes(key.slice(0, 20)))) return q;
  }
  return pool[(nextPhase - 1) % pool.length] || pool[0];
}

function isIntegrityTermination(answerText) {
  return /^\[system\s+termination/i.test(String(answerText || '').trim());
}

function isScorablePhaseRow(row) {
  if (!row || row.answer_text == null || row.score == null) return false;
  if (row.integrity_terminated || isIntegrityTermination(row.answer_text)) return false;
  const n = Number(row.score);
  return Number.isFinite(n);
}

function buildPhaseSummary(rows) {
  return rows
    .filter((row) => row.answer_text != null)
    .map((row) => {
      if (row.integrity_terminated || isIntegrityTermination(row.answer_text)) {
        return `P${row.phase}:integrity-fail`;
      }
      if (row.score != null) return `P${row.phase}:${row.score}`;
      return null;
    })
    .filter(Boolean)
    .join(', ');
}

function questionRelevanceCap(answerText, questionText) {
  const question = String(questionText || '').trim();
  if (!question || question.length < 20) return null;

  const tokens = question
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter((w) => w.length > 4);
  const stop = new Set([
    'would', 'could', 'should', 'their', 'there', 'which', 'about', 'describe',
    'explain', 'candidate', 'please', 'specific', 'technical', 'question',
    'implement', 'approach', 'system', 'using',
  ]);
  const keys = [...new Set(tokens.filter((w) => !stop.has(w)))].slice(0, 18);
  if (keys.length < 3) return null;

  const lower = String(answerText || '').toLowerCase();
  const hits = keys.filter((k) => lower.includes(k)).length;
  const ratio = hits / keys.length;

  if (ratio < 0.06) return 12;
  if (ratio < 0.12) return 22;
  if (ratio < 0.2) return 32;
  return null;
}

/** Clamp LLM scores — off-topic and garbage answers must not get free points */
function normalizePhaseScore(answerText, llmScore, questionText) {
  const answer = String(answerText || '').trim();
  let score = Number(llmScore);
  if (!Number.isFinite(score)) score = 0;

  if (!answer) return 0;
  if (isIntegrityTermination(answer)) return null;
  if (/^\[timeout/i.test(answer)) return 0;

  const relevanceCap = questionRelevanceCap(answer, questionText);
  if (relevanceCap != null) score = Math.min(score, relevanceCap);

  const lower = answer.toLowerCase().replace(/\s+/g, ' ').trim();
  const compact = answer.replace(/\s+/g, '');
  const len = compact.length;

  // Keyboard mash: mmmm, qqqqq, ooooo (same char repeated)
  if (len >= 4) {
    const chars = compact.toLowerCase().split('');
    const freq = {};
    for (const c of chars) freq[c] = (freq[c] || 0) + 1;
    const top = Math.max(...Object.values(freq));
    if (Object.keys(freq).length === 1 || top / chars.length >= 0.8) return 0;
  }

  // Trivial non-answers
  if (/^(ok|okay|yes|no|n\/a|na|idk|dunno|sure|fine|\.+|-+)$/i.test(lower)) {
    return Math.min(score, 3);
  }
  if (/^(ok\s+ok|yes\s+yes|no\s+no)$/i.test(lower)) {
    return Math.min(score, 3);
  }

  const techMarkers =
    /\b(api|sql|database|entity|framework|asp\.net|\.net|core|jwt|controller|service|schema|ef\s*core|linq|rest|dto|validation|fluentvalidation|dependency|injection|tenant|auth|middleware|repository|campaign|promotion|bcrypt|rbac|sso|endpoint|migration|index|query|table|class|interface|async|await)\b/i;

  const wordCount = lower.split(/\s+/).filter(Boolean).length;

  // One-liner generic with no technical terms (e.g. phase 1 "yes, system handles products...")
  if (wordCount <= 25 && !techMarkers.test(answer)) {
    return Math.min(score, 15);
  }

  // Very short, no technical signal
  if (len < 30 && !techMarkers.test(answer)) {
    return Math.min(score, 8);
  }

  // Short answer without technical depth — cap generous LLM scores
  if (len < 120 && !techMarkers.test(answer)) {
    return Math.min(score, 18);
  }

  if (len < 200 && score > 40 && !techMarkers.test(answer)) {
    return Math.min(score, 25);
  }

  return Math.max(0, Math.min(100, Math.round(score)));
}

function pickNodeJson(...names) {
  for (const name of names) {
    if (!name) continue;
    try {
      const raw = $(name).first().json;
      if (raw && typeof raw === 'object') return raw;
    } catch (_) {}
  }
  return null;
}

function pickBuildContext() {
  const built =
    pickNodeJson('CODE - Build LLM context', 'CODE - Build LLM context1') || {};

  if (built.session?.id && built.norm) return built;

  const norm =
    pickNodeJson('CODE - Normalize Data', 'CODE - Normalize Data1') || {};
  const fetchRaw = pickNodeJson('HTTP - Fetch Session', 'HTTP - Fetch Session1');
  const session = Array.isArray(fetchRaw) ? fetchRaw[0] : fetchRaw;

  if (session?.id) {
    let history = session.interview_history;
    if (typeof history === 'string') {
      try {
        history = JSON.parse(history);
      } catch (_) {
        history = [];
      }
    }
    return {
      session: { ...session, interview_history: history },
      norm,
    };
  }

  throw new Error(
    'Session context missing. Wire CODE - Build LLM context before Parse Result, or rename node to match (no stray "1" suffix).'
  );
}

function parseSessionConfig(raw) {
  if (!raw) return {};
  if (typeof raw === 'string') {
    try {
      return JSON.parse(raw);
    } catch (_) {
      return {};
    }
  }
  return typeof raw === 'object' ? raw : {};
}

function resolveWorkflowConfig(current, session, built) {
  const cfgNode =
    pickNodeJson('CFG - Assessment Config', 'CFG - Assessment Config1') || {};
  const normCfg = current?.config || {};
  const sessionCfg = parseSessionConfig(session?.config);
  const builtCfg = built?.norm?.config || {};

  const supabase_url =
    normCfg.supabase_url ||
    sessionCfg.supabase_url ||
    builtCfg.supabase_url ||
    cfgNode.supabase_url ||
    cfgNode.config?.supabase_url ||
    '';

  const supabase_key =
    normCfg.supabase_key ||
    sessionCfg.supabase_key ||
    builtCfg.supabase_key ||
    cfgNode.supabase_key ||
    cfgNode.config?.supabase_key ||
    '';

  return {
    ...cfgNode,
    ...builtCfg,
    ...sessionCfg,
    ...normCfg,
    supabase_url,
    supabase_key,
  };
}

const llm = $input.first().json;
const built = pickBuildContext();
const session = built.session;
const current = built.norm;
const cfg = resolveWorkflowConfig(current, session, built);
const content = parseLlmContent(llm);

let history = session.interview_history;
if (typeof history === 'string') {
  try {
    history = JSON.parse(history);
  } catch (err) {
    history = [];
  }
}
if (!Array.isArray(history)) history = [];

const ph = Number(current.current_phase || 1);
const maxQ = Number(cfg.max_questions || 5);
const failThreshold = Number(cfg.fail_score_threshold ?? 30);
const passThreshold = Number(cfg.pass_score_threshold ?? 60);
const iso = new Date().toISOString();

const integrityTerminated = isIntegrityTermination(current.answer);
const rawLlmScore = Number(content.score ?? 0);
let normalizedScore = null;
let scoreAdjusted = false;

const questionForPhase = String(
  history.find((x) => Number(x.phase) === ph)?.question_text ||
    history.find((x) => Number(x.phase) === ph)?.question ||
    built.current_question_text ||
    ''
).trim();

if (integrityTerminated) {
  normalizedScore = null;
} else {
  normalizedScore = normalizePhaseScore(current.answer, rawLlmScore, questionForPhase);
  scoreAdjusted = normalizedScore !== Math.round(rawLlmScore);
}

let idx = history.findIndex((x) => Number(x.phase) === ph);
const patch = {
  answer_text: current.answer,
  received_at: iso,
  feedback: content.feedback || null,
  suggested_answer: content.suggested_answer || content.suggestedAnswer || null,
  score: normalizedScore,
  integrity_terminated: integrityTerminated || undefined,
};
if (integrityTerminated) {
  patch.feedback =
    `Integrity violation on phase ${ph} — this phase is not scored. Prior completed phases keep their recorded scores.`;
} else if (scoreAdjusted && normalizedScore < rawLlmScore) {
  const relCap = questionRelevanceCap(current.answer, questionForPhase);
  patch.feedback = [
    patch.feedback,
    relCap != null && relCap <= 32
      ? `[Score adjusted ${rawLlmScore}→${normalizedScore}: answer did not address the question asked.]`
      : `[Score adjusted ${rawLlmScore}→${normalizedScore}: answer lacks required technical substance.]`,
  ]
    .filter(Boolean)
    .join(' ');
}

if (idx >= 0) history[idx] = { ...history[idx], ...patch };
else history.push({ phase: ph, question_text: '', sent_at: iso, ...patch });

const getPhaseScore = (phase) => {
  const row = history.find((x) => Number(x.phase) === phase);
  if (!row || row.answer_text == null || row.score == null) return null;
  const n = Number(row.score);
  return Number.isFinite(n) ? n : null;
};

function computeAverageScore(rows, maxPhases) {
  const scores = rows
    .filter((row) => {
      const phase = Number(row.phase);
      if (!Number.isFinite(phase) || phase < 1 || phase > maxPhases) return false;
      return isScorablePhaseRow(row);
    })
    .map((row) => Number(row.score));
  if (!scores.length) return null;
  return Math.round(scores.reduce((a, b) => a + b, 0) / scores.length);
}

// Run all maxQ phases — no early exit on low scores (final PASS/FAIL only on phase maxQ).
const earlyTerminate = false;
const earlyTerminateReason = '';

let nextQ = String(content.nextQuestion || content.next_question || '').trim();
let timeLimitSeconds = null;
let complexityTier = null;

// LLM sometimes omits next_question (esp. phase 4→5). Recover from history, then fallback.
let usedFallbackQuestion = false;
if (!nextQ && ph < maxQ && !integrityTerminated) {
  const existingNext = history.find(
    (x) => Number(x.phase) === ph + 1 && String(x.question_text || x.question || '').trim()
  );
  if (existingNext) {
    nextQ = String(existingNext.question_text || existingNext.question || '').trim();
    timeLimitSeconds = existingNext.time_limit_seconds ?? null;
    complexityTier = existingNext.complexity_tier ?? null;
  } else {
    nextQ = buildFallbackNextQuestion(ph, history, cfg, session);
    usedFallbackQuestion = Boolean(nextQ);
    if (usedFallbackQuestion) {
      content.feedback = [
        content.feedback || '',
        `[System: AI omitted phase ${ph + 1} question — auto-generated CV-grounded fallback.]`,
      ]
        .filter(Boolean)
        .join(' ');
    }
  }
}

const isActualFinalPhase = ph >= maxQ;

// Ignore premature LLM finished/PASS/FAIL before the last phase.
if (!isActualFinalPhase) {
  if (content.status === 'finished') content.status = 'in_progress';
  content.result = '';
}

let isFinal = isActualFinalPhase || integrityTerminated;

if (integrityTerminated) {
  nextQ = '';
  content.result = 'FAIL';
}

if (nextQ && ph < maxQ && !integrityTerminated) {
  const llmTier = content.complexity_tier || content.complexityTier || null;
  const derived = deriveTimeLimitSeconds(
    content.time_limit_seconds,
    llmTier,
    nextQ,
    cfg,
    ph + 1
  );
  timeLimitSeconds = derived.seconds;
  complexityTier = derived.tier;
}

if (nextQ && !isFinal) {
  const sentAt = iso;
  const nextPhase = ph + 1;
  const existingIdx = history.findIndex((x) => Number(x.phase) === nextPhase);
  const nextEntry = {
    phase: nextPhase,
    question_text: nextQ,
    answer_text: null,
    sent_at: sentAt,
    received_at: null,
    score: null,
    suggested_answer: null,
    feedback: null,
    time_limit_seconds: timeLimitSeconds,
    complexity_tier: complexityTier,
    deadline_at: timeLimitSeconds ? buildDeadline(sentAt, timeLimitSeconds) : null,
  };
  if (existingIdx >= 0) {
    history[existingIdx] = { ...history[existingIdx], ...nextEntry };
  } else {
    history.push(nextEntry);
  }
}

// Before final phase: missing next question must not end the assessment.
if (ph < maxQ && !integrityTerminated && !nextQ) {
  isFinal = false;
  content.feedback = [
    content.feedback || '',
    `[System: model did not return phase ${ph + 1} question — submit again or contact support.]`,
  ]
    .filter(Boolean)
    .join(' ');
}

const phaseScore = normalizedScore;

if (isActualFinalPhase && !integrityTerminated) {
  if (content.status === 'finished' || content.result) isFinal = true;
  if (!content.result) {
    const avg = computeAverageScore(history, maxQ);
    const finalScore =
      avg ?? (Number.isFinite(phaseScore) && phaseScore != null ? phaseScore : 0);
    content.result = finalScore >= passThreshold ? 'PASS' : 'FAIL';
  }
}

const body = { interview_history: history, updated_at: iso };
if (nextQ && !isFinal) body.current_phase = ph + 1;
else if (!isFinal) body.current_phase = ph;
else body.current_phase = ph;

const averageScore = computeAverageScore(history, maxQ);

let finalResult = null;
let finalFeedback = content.feedback || '';
if (isFinal) {
  body.status = 'completed';
  const finalScore =
    averageScore ??
    (Number.isFinite(phaseScore) && phaseScore != null ? phaseScore : null) ??
    0;
  body.score = finalScore;

  if (integrityTerminated) {
    body.result = 'FAIL';
    finalResult = 'FAIL';
    const phaseSummary = buildPhaseSummary(history);
    finalFeedback = [
      `Assessment failed: integrity violation on phase ${ph}.`,
      averageScore != null
        ? `Recorded average from completed phases before termination: ${averageScore}/100 (${phaseSummary}).`
        : `No prior scored phases (${phaseSummary || 'none'}).`,
    ]
      .filter(Boolean)
      .join(' ');
  } else if (earlyTerminate) {
    body.result = 'FAIL';
    finalResult = 'FAIL';
    const phaseSummary = buildPhaseSummary(history);
    if (averageScore != null) {
      finalFeedback = [
        finalFeedback,
        `Average score across completed phases: ${averageScore}/100 (${phaseSummary}). Pass mark: ${passThreshold}.`,
      ]
        .filter(Boolean)
        .join(' ');
    }
  } else {
    body.result = finalScore >= passThreshold ? 'PASS' : 'FAIL';
    finalResult = body.result;
    if (averageScore != null) {
      const phaseSummary = buildPhaseSummary(history);
      finalFeedback = [
        finalFeedback,
        `Average score across all phases: ${averageScore}/100 (${phaseSummary}). Pass mark: ${passThreshold}.`,
      ]
        .filter(Boolean)
        .join(' ');
    }
  }
}

const b = String(cfg.supabase_url || '').replace(/\/+$/, '');
if (!b || !/^https?:\/\//i.test(b)) {
  throw new Error(
    'supabase_url missing or invalid. Set top-level supabase_url in CFG - Assessment Config (e.g. https://xxx.supabase.co).'
  );
}
const patchUrl = `${b}/rest/v1/assessment_sessions?id=eq.${encodeURIComponent(String(session.id))}`;
const nextRow = history.find((x) => Number(x.phase) === ph + 1);

return [
  {
    json: {
      score: isFinal ? (body.score ?? averageScore ?? phaseScore) : phaseScore,
      phase_score: phaseScore,
      llm_score_raw: rawLlmScore,
      score_adjusted: scoreAdjusted,
      average_score: isFinal ? (body.score ?? averageScore) : null,
      feedback: isFinal ? finalFeedback : (patch.feedback || content.feedback || ''),
      nextQuestion: nextQ,
      suggested_answer: content.suggested_answer || content.suggestedAnswer || '',
      time_limit_seconds: nextRow?.time_limit_seconds ?? timeLimitSeconds,
      deadline_at: nextRow?.deadline_at ?? null,
      complexity_tier: nextRow?.complexity_tier ?? complexityTier,
      isFinal,
      result: isFinal ? finalResult : null,
      terminatedEarly: earlyTerminate,
      integrity_terminated: integrityTerminated,
      candidate_email: current.candidate_email,
      session_id: current.session_id || session.id,
      current_phase: ph,
      config: cfg,
      gmail_thread_id: session.gmail_thread_id || null,
      gmail_message_id: session.gmail_message_id || null,
      mail_subject: session.mail_subject || null,
      _session_patch_url: patchUrl,
      _session_patch_body: body,
    },
  },
];

